VALUES
  ('heelevel3-53250add-moex-00052', 'heelevel3-53250add', 'heelevel3-53250add-moex-114-3082b5f1', 'sub-heelevel3-53250add-03', NULL, 'single_choice', '甲、乙、丙、丁、戊、己等6人共同提起訴願，依訴願法規定，下列敘述何者錯誤？', '["甲等6人因同一原因事實，受課稅處分，得共同提起訴願", "甲、乙為訴願選定代表人，則甲、乙均得單獨代表共同訴願人為訴願行為", "甲等6人經通知逾期未選定訴願代表人，受理訴願機關得依職權指定訴願代表人", "甲等6人共同提起訴願，得選定甲、乙、丙、丁為代表人"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:03+00:00", "source_pdf_sha1": "1959a582ef2c", "answer_pdf_sha1": "940b0a4bb83c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "235", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "智慧財產行政"}'::jsonb, NULL),
  ('heelevel3-53250add-moex-00053', 'heelevel3-53250add', 'heelevel3-53250add-moex-114-3082b5f1', 'sub-heelevel3-53250add-03', NULL, 'single_choice', '國家成立鹽業公司，販賣國民海洋深層水。下列敘述何者正確？', '["該公司不得主張契約自由", "若其產品發生食安事件，不得請求國家賠償", "國家得以公法法規管制該交易", "該交易應受行政法原則之約束"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:03+00:00", "source_pdf_sha1": "1959a582ef2c", "answer_pdf_sha1": "940b0a4bb83c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "235", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "智慧財產行政"}'::jsonb, NULL),
  ('heelevel3-53250add-moex-00054', 'heelevel3-53250add', 'heelevel3-53250add-moex-114-3082b5f1', 'sub-heelevel3-53250add-03', NULL, 'single_choice', '依司法院大法官解釋或憲法法庭裁判意旨，下列何者之救濟應提起課予義務訴訟？', '["教師因違反教師法遭聘任學校決定自次一學年起不予續聘", "本國人就其外國籍配偶依法申請入境遭駁回處分", "教師因體罰學生遭決議解聘且4年內不得擔任教師，經主管機關核准", "人民依法請求就國有林地中濫墾地訂立租地契約遭拒絕"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:03+00:00", "source_pdf_sha1": "1959a582ef2c", "answer_pdf_sha1": "940b0a4bb83c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "235", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "智慧財產行政"}'::jsonb, NULL),
  ('heelevel3-53250add-moex-00055', 'heelevel3-53250add', 'heelevel3-53250add-moex-114-3082b5f1', 'sub-heelevel3-53250add-03', NULL, 'single_choice', '甲為中華民國國籍人士，其與A國籍乙在A國辦理結婚登記。嗣後乙持A國結婚證書向我國駐 A國代表處申請驗證結婚證書及核發依親居留簽證。然而我國駐A國代表處卻認為，甲與乙在面 談時對於結婚重要事實陳述不一致，因此駁回乙之簽證申請。依司法實務之見解，下列敘述何者 正確？', '["甲得以自己名義提起課予義務訴訟，請求發給乙簽證", "乙不具有我國國籍，因此無法提起行政救濟", "甲得以自己名義，提起撤銷訴願及撤銷訴訟，以資救濟", "因為甲本身並非依法得申請簽證之當事人，因此無法提起行政救濟"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:03+00:00", "source_pdf_sha1": "1959a582ef2c", "answer_pdf_sha1": "940b0a4bb83c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "235", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "智慧財產行政"}'::jsonb, NULL),
  ('heelevel3-53250add-moex-00056', 'heelevel3-53250add', 'heelevel3-53250add-moex-114-3082b5f1', 'sub-heelevel3-53250add-03', NULL, 'single_choice', '下列何種情形國家不負損害賠償責任？', '["甲國家公園管理機關因颱風警報，在所屬國家公園登山口公告禁止入山，乙因假期難得，仍冒 險登山而發生山難", "丙機關設立之公園鞦韆已經壞損，不堪使用，故在該鞦韆旁標示不得使用，丁仍讓其未成年之 子女戊使用，戊不幸拋飛而受有重傷", "主管機關平日未巡視公園樹木狀況，因強烈颱風來襲，致樹木倒塌壓傷路過之民眾", "土地登記機關因可歸責之事由，發生登記錯誤"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:03+00:00", "source_pdf_sha1": "1959a582ef2c", "answer_pdf_sha1": "940b0a4bb83c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "235", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "智慧財產行政"}'::jsonb, NULL),
  ('heelevel3-53250add-moex-00057', 'heelevel3-53250add', 'heelevel3-53250add-moex-114-3082b5f1', 'sub-heelevel3-53250add-03', NULL, 'single_choice', '依司法實務見解，公共事業之設施穿越私有土地之地下，致逾越所有權人社會責任所應忍受範圍， 形成個人之特別犧牲時，下列敘述何者正確？', '["土地所有權人得請求需用土地人向主管機關申請徵收地上權", "所有權人之土地所有權並未受剝奪，故應忍受此一財產權社會義務的合法限制", "此屬財產權之違法侵害，當事人應請求除去侵害", "無法律則無徵收補償，若法律未有規定時，所有權人不得請求需用土地人向主管機關申請徵收"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:03+00:00", "source_pdf_sha1": "1959a582ef2c", "answer_pdf_sha1": "940b0a4bb83c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "235", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "智慧財產行政"}'::jsonb, NULL),
  ('heelevel3-53250add-moex-00058', 'heelevel3-53250add', 'heelevel3-53250add-moex-113-b6671682', 'sub-heelevel3-53250add-01', NULL, 'essay', '因應消費者需求型態的改變，各大業者推出生鮮送貨到家的服務，比如
A 超市的小時達、B 量販店的生鮮宅配，兩者的購物型態極為相似，都
是透過業者的 App 搜尋商品後，由平台協助送貨，但又有些許不同，比
如受限於店舖家數與外送距離等。小時達是 A超市推出的「生鮮外送服
務」，達新臺幣 399 元免運，最快30 分鐘送到家，不僅合作外送平台，
也在旗下電商平台推出服務，消費者輸入所在位置即可開始選購；而 B
量販店的生鮮宅配與外送平台合作，消費者只要輸入預計配送的地址
後，搜尋 B量販店，只要消費者所在位置在配送範圍內，即可透過外送
平台選購商品，並由外送平台協助送貨到府。請試述公平交易法上界定
相關市場之意義，並舉出具體之相關市場界定方法，分析判斷 A超市小
時達與 B 量販店生鮮宅配兩種購物方式是否屬於同一地理市場。（倘若
題旨所述事實資料有所不足，作答時可透過假設予以補充）（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:03+00:00", "source_pdf_sha1": "318589c1b27e", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "331", "s": "1017", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "公平交易法", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "智慧財產行政"}'::jsonb, NULL),
  ('heelevel3-53250add-moex-00059', 'heelevel3-53250add', 'heelevel3-53250add-moex-113-b6671682', 'sub-heelevel3-53250add-01', NULL, 'essay', '市場交易屬於契約自由之行為，而企業因競爭而有差別待遇之手段，亦
屢見於商業慣行，是市場競爭的必然情況。然而，並非所有差別待遇都
需要管制，僅有當企業非基於「正當理由」而為差別待遇，且其效果有
限制競爭之虞，才構成公平交易法第 20 條第 2 款之違反。請說明公平
交易法第20 條第 2 款所謂的差別待遇「正當理由」之判斷要件。（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:03+00:00", "source_pdf_sha1": "318589c1b27e", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "331", "s": "1017", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "公平交易法", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "智慧財產行政"}'::jsonb, NULL),
  ('heelevel3-53250add-moex-00060', 'heelevel3-53250add', 'heelevel3-53250add-moex-113-b6671682', 'sub-heelevel3-53250add-01', NULL, 'essay', '某 A 建商銷售「未來山林」預售屋建案，廣告刊載「萬坪公園首排」、
「2 萬坪樹海第一排」、「環狀線 D25 站散步抵達本建案 5 分鐘至 Y25 站
預定地」等，由於建案對街為臺北市某知名小學，是以某甲認為地段良
好、公園首排且有利於小孩就學，故而下訂。然事後某甲發現有好多個
與廣告不符之處，諸如建案所在地距離「環狀線 D25 站」步行約 13 分
鐘，其次本建案四周尚未有其他建案或遮蔽物，以現有對街國小與相鄰
公園四周樹林栽種面積加總未達 1 萬坪，與廣告所稱「2 萬坪樹海第一
排」明顯有落差。試述某甲可否主張公平交易法第21 條不實廣告，並要
求取消契約。（25 分）
33140', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:03+00:00", "source_pdf_sha1": "318589c1b27e", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "331", "s": "1017", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "公平交易法", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": "三", "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "智慧財產行政"}'::jsonb, NULL),
  ('heelevel3-53250add-moex-00061', 'heelevel3-53250add', 'heelevel3-53250add-moex-113-b6671682', 'sub-heelevel3-53250add-01', NULL, 'essay', '有關公平交易法第 14 條規定，參與聯合行為之事業，於相關市場之市場
占有率總和未達10％者，推定不足以影響生產、商品交易或服務供需之
市場功能。此即公平交易委員會將對市場供需功能影響程度輕微之聯合
行為，界定為「聯合行為微小不罰案件」，得豁免聯合行為禁制規範之適
用。請分別就「量」與「質」說明「聯合行為微小不罰案件」之認定標
準。（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:03+00:00", "source_pdf_sha1": "318589c1b27e", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "331", "s": "1017", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "公平交易法", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": "四", "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "智慧財產行政"}'::jsonb, NULL)
